### HTML Form

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Secure Web Form</title>
    <script src="https://cdn.jsdelivr.net/npm/htmlpurify@6.0.0/dist/html.min.js"></script>
    <style>
        .error {
            color: red;
        }
    </style>
</head>
<body>
    <h1>Secure Web Form</h1>
    <form id="secureForm" method="POST" action="process_form.php">
        <div>
            <label for="name">Name:</label>
            <input type="text" id="name" name="name" required>
            <span id="nameError" class="error"></span>
        </div>
        <div>
            <label for="email">Email:</label>
            <input type="email" id="email" name="email" required>
            <span id="emailError" class="error"></span>
        </div>
        <div>
            <label for="password">Password:</label>
            <input type="password" id="password" name="password" required>
            <span id="passwordError" class="error"></span>
        </div>
        <div>
            <label for="confirmPassword">Confirm Password:</label>
            <input type="password" id="confirmPassword" name="confirmPassword" required>
            <span id="confirmPasswordError" class="error"></span>
        </div>
        <button type="submit">Submit</button>
    </form>

    <script>
        document.getElementById('secureForm').addEventListener('submit', function(event) {
            event.preventDefault();
            const name = document.getElementById('name').value;
            const email = document.getElementById('email').value;
            const password = document.getElementById('password').value;
            const confirmPassword = document.getElementById('confirmPassword').value;

            let isValid = true;

            // Client-side validation
            if (!name || name.trim() === '') {
                document.getElementById('nameError').innerText = 'Name is required';
                isValid = false;
            } else {
                document.getElementById('nameError').innerText = '';
            }

            if (!email || !validateEmail(email)) {
                document.getElementById('emailError').innerText = 'Invalid email address';
                isValid = false;
            } else {
                document.getElementById('emailError').innerText = '';
            }

            if (!password || password.length < 8) {
                document.getElementById('passwordError').innerText = 'Password must be at least 8 characters long';
                isValid = false;
            } else {
                document.getElementById('passwordError').innerText = '';
            }

            if (password !== confirmPassword) {
                document.getElementById('confirmPasswordError').innerText = 'Passwords do not match';
                isValid = false;
            } else {
                document.getElementById('confirmPasswordError').innerText = '';
            }

            if (isValid) {
                // Proceed with form submission
                this.submit();
            }
        });

        function validateEmail(email) {
            const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            return re.test(String(email).toLowerCase());
        }
    </script>
</body>
</html>
```

### PHP Script for Processing the Form (`process_form.php`)

```php
<?php
// process_form.php

// Initialize variables
$name = $email = $password = '';

// Check if the form was submitted
if ($_SERVER["REQUEST_METHOD"] == "POST") {
    // Sanitize and validate inputs
    $name = htmlspecialchars($_POST['name']);
    $email = filter_var($_POST['email'], FILTER_SANITIZE_EMAIL);
    $password = $_POST['password'];
    $confirmPassword = $_POST['confirmPassword'];

    // Server-side validation
    if (empty($name)) {
        die("Name is required");
    }

    if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
        die("Invalid email address");
    }

    if (strlen($password) < 8) {
        die("Password must be at least 8 characters long");
    }

    if ($password !== $confirmPassword) {
        die("Passwords do not match");
    }

    // Store the data securely (e.g., in a database)
    $servername = "localhost";
    $username = "root";
    $password_db = "your_password";
    $dbname = "your_database";

    // Create connection
    $conn = new mysqli($servername, $username, $password_db, $dbname);

    // Check connection
    if ($conn->connect_error) {
        die("Connection failed: " . $conn->connect_error);
    }

    // Prepare and bind
    $stmt = $conn->prepare("INSERT INTO users (name, email, password) VALUES (?, ?, ?)");
    $stmt->bind_param("sss", $name, $email, $password);

    // Execute the statement
    if ($stmt->execute()) {
        echo "New record created successfully";
    } else {
        echo "Error: " . $stmt->error;
    }

    // Close the statement and connection
    $stmt->close();
    $conn->close();
}
?>
```

### Explanation

1. **HTML Form**:
   - The form includes fields for name, email, password, and confirm password.
   - Client-side validation ensures that the form is filled out correctly before submission.
   - Error messages are displayed next to each field if validation fails.

2. **JavaScript**:
   - Validates the form fields on the client side.
   - Prevents form submission if any validation fails.
   - Provides immediate feedback to the user.

3. **PHP Script**:
   - Handles the form submission on the server side.
   - Sanitizes and validates inputs.
   - Stores the data securely in a MySQL database.
   - Uses prepared statements to prevent SQL injection.

This setup demonstrates how to implement various best practices for secure web forms, including client-side and server-side validation, input sanitization, and secure data storage.

