#### 2. JavaScript (AJAX)
Next, we'll add the JavaScript to handle form submission and AJAX requests. This script will validate the form on the client side and send the data to the server using AJAX.

```javascript
document.getElementById('myForm').addEventListener('submit', function(event) {
    event.preventDefault(); // Prevent the default form submission

    const name = document.getElementById('name').value;

    if (!name) {
        document.getElementById('message').textContent = 'Please enter your name.';
        return;
    }

    // Send the data to the server using AJAX
    fetch('/save-name', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({ name })
    })
    .then(response => response.json())
    .then(data => {
        document.getElementById('message').textContent = data.message;
    })
    .catch(error => {
        console.error('Error:', error);
        document.getElementById('message').textContent = 'An error occurred. Please try again later.';
    });
});
```

#### 3. Node.js and Express Backend
Finally, we'll set up a simple Node.js backend using Express to handle the form submission and save the data.

**Install Dependencies:**
```sh
npm init -y
npm install express body-parser
```

**Create `server.js`:**

```javascript
const express = require('express');
const bodyParser = require('body-parser');

const app = express();
const port = 3000;

// Middleware to parse JSON bodies
app.use(bodyParser.json());

// Route to handle form submission
app.post('/save-name', (req, res) => {
    const { name } = req.body;

    // Save the name to a file or database (for simplicity, we'll just log it here)
    console.log(`Received name: ${name}`);

    // Respond with a success message
    res.json({ message: 'Name saved successfully!' });
});

// Start the server
app.listen(port, () => {
    console.log(`Server running on http://localhost:${port}`);
});
```

